import yaml
import os
import json
import re

def parse_frontmatter(filepath):
    with open(filepath, 'r') as f:
        content = f.read()
    # Match YAML frontmatter between ---
    m = re.match(r'^---\s*\n(.*?)\n---', content, re.DOTALL)
    if not m:
        return None
    try:
        data = yaml.safe_load(m.group(1))
        return data
    except Exception as e:
        return {'_error': str(e), '_file': filepath}

results = {'concepts': [], 'connections': []}

for folder in ['concepts', 'connections']:
    dirpath = os.path.join('/opt/data/FirmVault/wiki', folder)
    if not os.path.isdir(dirpath):
        continue
    for fname in sorted(os.listdir(dirpath)):
        if not fname.endswith('.md'):
            continue
        fpath = os.path.join(dirpath, fname)
        fm = parse_frontmatter(fpath)
        if fm:
            fm['_folder'] = folder
            fm['_filename'] = fname.replace('.md', '')
            results[folder].append(fm)

print(json.dumps(results, default=str, indent=2))
